def _mean_channel_delta(left: bytes, right: bytes) -> float:
    if len(left) != len(right):
        raise ValueError("Raster sizes differ.")
    total = 0
    for index in range(len(left)):
        total += abs(left[index] - right[index])
    return total / len(left)
